    medications: [
      { name: "Haloperidol", type: "Typical Antipsychotic (Butyrophenone)", action: "Blocks dopamine D2 receptors in the mesolimbic pathway, reducing agitation, hallucinations, and psychomotor disturbance in delirium", sideEffects: "QTc prolongation, extrapyramidal symptoms, neuroleptic malignant syndrome", contra: "Baseline QTc >500 ms, Parkinson disease, Lewy body dementia", pearl: "Use lowest effective dose (0.5-1 mg IV/PO). Obtain baseline ECG. Not FDA-approved for delirium but widely used off-label for severe agitation." },
      { name: "Dexmedetomidine (Precedex)", type: "Alpha-2 Adrenergic Agonist", action: "Provides sedation without respiratory depression by acting on locus coeruleus, preserving natural sleep architecture and reducing delirium incidence in ICU", sideEffects: "Bradycardia, hypotension", contra: "Advanced heart block, severe hemodynamic instability", pearl: "Preferred over benzodiazepines for ICU sedation to reduce delirium risk per PADIS guidelines." }
    ],
    pearls: ["Hypoactive delirium is the most common subtype but is frequently missed because patients appear calm and withdrawn", "Benzodiazepines cause and worsen delirium in most patients—reserve only for alcohol withdrawal or benzodiazepine withdrawal", "Delirium is a medical emergency: it is independently associated with increased mortality, prolonged hospitalization, and long-term cognitive decline"],
    quiz: [
      { question: "A 78-year-old postoperative hip fracture patient is alert in the morning but becomes confused and agitated in the evening, pulling at IV lines and stating 'there are bugs on the wall.' The CAM screen is positive. Which intervention should the nurse implement first?", options: ["Apply bilateral wrist restraints to prevent line removal", "Administer lorazepam 2 mg IV for agitation", "Reorient the patient, ensure glasses and hearing aids are in place, and dim overhead lights", "Request a psychiatry consult for new-onset psychosis", "Obtain a CT scan of the head immediately"], correct: 2, rationale: "Non-pharmacological interventions are first-line for delirium management. Reorientation, sensory aids, and environmental modifications address modifiable risk factors. Restraints and benzodiazepines worsen delirium." },
      { question: "Which validated screening tool should the nurse use to assess delirium in an intubated ICU patient?", options: ["Mini-Mental State Examination (MMSE)", "Montreal Cognitive Assessment (MoCA)", "Confusion Assessment Method for the ICU (CAM-ICU)", "Glasgow Coma Scale (GCS)", "PHQ-9 Depression Screen"], correct: 2, rationale: "The CAM-ICU is specifically designed for non-verbal and mechanically ventilated patients. It assesses acute onset, inattention, altered level of consciousness, and disorganized thinking without requiring verbal responses." },
      { question: "A nurse reviews the medication list of an elderly patient newly diagnosed with delirium. Which medication is most likely contributing to the delirium?", options: ["Lisinopril 10 mg daily", "Diphenhydramine 50 mg at bedtime for insomnia", "Metoprolol 25 mg twice daily", "Aspirin 81 mg daily", "Atorvastatin 40 mg at bedtime"], correct: 1, rationale: "Diphenhydramine is a potent anticholinergic agent. Anticholinergic medications are a leading modifiable cause of delirium, especially in elderly patients. It should be discontinued and replaced with a non-anticholinergic alternative." },
      { question: "Which subtype of delirium is most frequently underdiagnosed in hospitalized patients?", options: ["Hyperactive delirium with agitation and hallucinations", "Hypoactive delirium with lethargy and withdrawal", "Mixed delirium alternating between agitation and sedation", "Emergent delirium following general anesthesia", "Substance-induced delirium with tremors"], correct: 1, rationale: "Hypoactive delirium accounts for up to 75% of cases but is often missed because patients appear quiet, sleepy, and compliant. Routine CAM screening is essential to detect this subtype." },
      { question: "An ICU nurse is implementing evidence-based delirium prevention strategies. Which nursing intervention is supported by the ABCDEF bundle?", options: ["Administer prophylactic haloperidol to all ICU patients over age 65", "Perform daily spontaneous awakening and breathing trials and promote early mobilization", "Maintain continuous deep sedation to ensure patient comfort", "Keep the ICU environment brightly lit 24 hours a day to maintain orientation", "Use physical restraints prophylactically to prevent self-extubation"], correct: 1, rationale: "The ABCDEF bundle includes daily spontaneous awakening trials (SAT), spontaneous breathing trials (SBT), choice of sedation, delirium monitoring, early mobility, and family engagement. These evidence-based strategies significantly reduce delirium incidence and duration." }
    ]
